const report = $input.first().json;
const variables = report.generated_data?.variables ?? {};
const existingSections = report.generated_data?.sections ?? [];
const existingMetadata = report.generated_data?.metadata ?? {};
const sections = existingSections.map((section, index) => ({
  id: section.id || section.key || `section-${index + 1}`,
  key: section.key || section.id || `section-${index + 1}`,
  number: section.number || String(index + 1),
  title: section.title,
}));
const schema = {
  type: 'object',
  additionalProperties: false,
  required: ['title', 'summary', 'sections', 'missing_points', 'image_suggestions'],
  properties: {
    title: { type: 'string' },
    summary: { type: 'string' },
    sections: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['id', 'number', 'title', 'content'],
        properties: {
          id: { type: 'string' },
          number: { type: 'string' },
          title: { type: 'string' },
          content: { type: 'string' }
        }
      }
    },
    missing_points: {
      type: 'array',
      items: { type: 'string' }
    },
    image_suggestions: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['section_id', 'caption', 'reason'],
        properties: {
          section_id: { type: 'string' },
          caption: { type: 'string' },
          reason: { type: 'string' }
        }
      }
    }
  }
};
const promptContext = {
  report_id: report.id,
  title: report.title,
  report_number: report.report_number,
  report_type: report.type,
  project: report.projects ?? null,
  template: report.report_templates ?? null,
  variables,
  sections,
};
const userPrompt = [
  'DADOS DO RELATORIO',
  JSON.stringify(promptContext, null, 2),
  '',
  'REGRAS DE REDACAO',
  '- Escreva em portugues do Brasil.',
  '- Monte uma primeira minuta tecnica para revisao humana.',
  '- Nao invente datas, numeros, nomes, resultados ou evidencias.',
  '- Se alguma informacao estiver faltando, deixe isso explicito de maneira profissional.',
  '- Mantenha o texto claro, enxuto e pronto para ser editado pelo tecnico.',
  '- Preencha todas as secoes recebidas, respeitando id, numero e titulo.',
  '- Retorne estritamente no schema solicitado.'
].join('\n');
return [
  {
    json: {
      report_id: report.id,
      report_title: report.title,
      existing_variables: variables,
      existing_sections: existingSections,
      existing_metadata: existingMetadata,
      openai_request: {
        model: process.env.OPENAI_MODEL || 'gpt-4.1-mini',
        input: [
          {
            role: 'system',
            content: [
              {
                type: 'input_text',
                text: 'Voce escreve minutas tecnicas da Elementus em portugues do Brasil. Organize relatos de campo em linguagem tecnica clara, objetiva e pronta para revisao humana. Nao invente medições, datas, nomes ou resultados que nao estejam no contexto. Se alguma informacao estiver incompleta, explicite a lacuna no texto de forma profissional. Responda estritamente no schema solicitado.'
              }
            ]
          },
          {
            role: 'user',
            content: [
              {
                type: 'input_text',
                text: userPrompt
              }
            ]
          }
        ],
        text: {
          format: {
            type: 'json_schema',
            name: 'elementus_report_generation',
            schema,
            strict: true
          }
        }
      }
    }
  }
];

const aiResponse = $input.first().json;
const requestContext = $('Build AI Request').first().json;
const reportFromApi = $('Get Report').first().json;
function tryParse(value) {
  if (!value) return null;
  if (typeof value === 'object') return value;
  if (typeof value !== 'string') return null;
  try {
    return JSON.parse(value);
  } catch {
    return null;
  }
}
let parsed = tryParse(aiResponse.output_text);
if (!parsed && Array.isArray(aiResponse.output)) {
  for (const outputItem of aiResponse.output) {
    for (const contentItem of outputItem.content || []) {
      parsed = tryParse(contentItem.json ?? contentItem.text ?? contentItem.output_text);
      if (parsed) break;
    }
    if (parsed) break;
  }
}
if (!parsed) {
  throw new Error('Nao foi possivel interpretar a resposta estruturada da OpenAI.');
}
const previousSections = requestContext.existing_sections || [];
const sections = (parsed.sections || []).map((section, index) => {
  const previous = previousSections.find((item) => (item.id || item.key) === section.id);
  return {
    id: section.id,
    key: section.id,
    number: section.number || String(index + 1),
    title: section.title,
    content: section.content,
    editable: true,
    edited: false,
    images: previous?.images || [],
  };
});
return [
  {
    json: {
      report_id: requestContext.report_id,
      webhook_response: {
        ok: true,
        report_id: requestContext.report_id,
        status: 'review'
      },
      patch_body: {
        title: parsed.title || requestContext.report_title || reportFromApi.title,
        status: 'review',
        generated_data: {
          sections,
          charts: [],
          tables: [],
          variables: requestContext.existing_variables || {},
          metadata: {
            ...(requestContext.existing_metadata || {}),
            ai_provider: 'openai',
            ai_workflow: 'n8n',
            ai_generated_at: new Date().toISOString(),
            ai_model: process.env.OPENAI_MODEL || 'gpt-4.1-mini',
            ai_summary: parsed.summary || '',
            ai_missing_points: parsed.missing_points || [],
            ai_image_suggestions: parsed.image_suggestions || [],
            n8n_generation_triggered: true,
            n8n_processed_at: new Date().toISOString()
          }
        }
      }
    }
  }
];
